queries.query:
from(bucket: "traffic_data")
  |> range(start: -30s) // Ultimi 30 secondi
  |> filter(fn: (r) => r._measurement == "stato_traffico")
  // Prendiamo il colore
  |> filter(fn: (r) => r._field == "colore")
  // L'ultimo stato noto per ogni semaforo
  |> last()
  // Riorganizziamo la tabella: incroci nelle righe, direzioni nelle colonne
  |> pivot(rowKey:["incrocio"], columnKey: ["direzione"], valueColumn: "_value")

from(bucket: "traffic_data")
  |> range(start: -5m) // Guardiamo gli ultimi 5 minuti
  |> filter(fn: (r) => r._measurement == "stato_traffico")
  // Filtriamo solo l'incrocio principale per non creare confusione (es. STAZIONE)
  |> filter(fn: (r) => r.incrocio == "INC_STAZIONE")
  // Prendiamo i due field che ci servono
  |> filter(fn: (r) => r._field == "auto_in_coda" or r._field == "durata_verde")
  // Aggreghiamo ogni 5 secondi (creando una media per linee fluide)
  |> aggregateWindow(every: 5s, fn: mean, createEmpty: false)
  // Pivottiamo per avere due colonne separate per i grafici
  |> pivot(rowKey:["_time"], columnKey: ["_field"], valueColumn: "_value")

from(bucket: "traffic_data")
  |> range(start: -1h) // Nell'ultima ora
  |> filter(fn: (r) => r._measurement == "stato_traffico")
  // Filtriamo l'incrocio speciale "CITTA"
  |> filter(fn: (r) => r.incrocio == "CITTA")
  // E il field del conteggio
  |> filter(fn: (r) => r._field == "count")
  // Sommiamo tutte le auto salvate nell'ora
  |> sum()

from(bucket: "traffic_data")
  |> range(start: -1m)
  |> filter(fn: (r) => r._measurement == "stato_traffico")
  |> filter(fn: (r) => r._field == "auto_in_coda")
  // Prendiamo solo l'ultimo dato per ogni semaforo
  |> last()
  // Raggruppiamo per incrocio (così sommiamo le code delle varie direzioni)
  |> group(columns: ["incrocio"])
  // Sommiamo le code (NORD+SUD+EST+OVEST)
  |> sum(column: "_value")
  // Raggruppiamo tutto insieme per fare la classifica globale
  |> group()
  // Ordiniamo decrescente (la coda peggiore in alto)
  |> sort(columns: ["_value"], desc: true)
  // Prendiamo i primi 5
  |> limit(n: 5)
